mapper.select:
select id, code, name, required, sms_enabled as smsEnabled, email_enabled as emailEnabled, totp_enabled as totpEnabled, webauthn_enabled as webauthnEnabled, remember_device_enabled as rememberDeviceEnabled, remember_device_days as rememberDeviceDays, risk_based_enabled as riskBasedEnabled, status, description, create_time, update_time from mfa_policy
and `name` like concat('%', #{request.name}, '%')
and `code` = #{request.code}
and `status` = #{request.status}
order by create_time desc
